SERVER=("118.25.42.70",9000)

def recv_exact(sock,size):
    out=bytearray()
    while len(out)<size:
        p=sock.recv(size-len(out))
        if not p: raise ConnectionError()
        out+=p
    return bytes(out)

def request(sock,op,body=b""):
    sock.sendall(bytes((op,))+len(body).to_bytes(4,"big")+body)
    h=recv_exact(sock,5)
    return h[0], recv_exact(sock,int.from_bytes(h[1:5],"big"))

def children(sock,parent):
