#define NAME_COMMON_H
#include <stdio.h>
#include <string.h>
#include <stdlib.h>
typedef unsigned char u8;
typedef unsigned u32;
typedef u8 H[32];

typedef struct { H token; char name[96]; } Entry;

/* Completion index from network tag graph (#TAG + children), cached aggressively. */
static Entry g_names[4096];
static u32 g_name_n;
static int g_name_loaded;

