        h[24],h[25],h[26],h[27],h[28],h[29],h[30],h[31]);
}

static int cache_file_size(const H h, u32 *out_sz) {
    char path[140];
    cache_bin_path(h, path, sizeof(path));
    FILE *f = fopen(path, "rb");
    if (!f) return 0;
    if (fseek(f, 0, SEEK_END) != 0) { fclose(f); return 0; }
    long n = ftell(f);
    fclose(f);
    if (n < 0) return 0;
    *out_sz = (u32)n;
    return 1;
