static int is_printable_buf(const u8 *p, u32 n) {
    if (!n || n >= 96) return 0;
    for (u32 i = 0; i < n; i++) if (p[i] < 32 || p[i] > 126) return 0;
    return 1;
}

static int is_tag_buf(const u8 *p, u32 n) {
    return is_printable_buf(p, n) && p[0] == '#';
}

static int is_name_buf(const u8 *p, u32 n) {
    return is_printable_buf(p, n) && p[0] != '#';
