/* install edges token -> ascii name blob; use that as display name without loading DLL. */
static int name_from_children(const H node, char *out, u32 outn) {
    H kids[32];
    u32 n = cvm_children(node, kids, 32);
    if (n > 32) n = 32;
    for (u32 i = 0; i < n; i++) {
        if (same32(kids[i], node)) continue;
        u32 sz = 0;
        if (cache_file_size(kids[i], &sz) && sz >= 96) continue;
        u8 buf[96];
        u32 rn = read_blob(kids[i], buf, sizeof(buf) - 1);
        if (rn >= 96) continue;
        u32 use = rn < sizeof(buf) - 1 ? rn : sizeof(buf) - 1;
        if (!is_name_buf(buf, use)) continue;
        if (use >= outn) use = outn - 1;
        memcpy(out, buf, use);
        out[use] = 0;
        return 1;
    }
    return 0;
}

