    H kids[64];
    u32 n = cvm_children(node, kids, 64);
    if (n > 64) n = 64;
    u32 c = 0;
    for (u32 i = 0; i < n; i++) if (!same32(kids[i], node) && !zero32(kids[i])) c++;
