                u32 use = rn < sizeof(buf) - 1 ? rn : sizeof(buf) - 1;
                if (rn >= 96) {
                    hex4_name(kids[i], nm, sizeof(nm));
                    add_entry(kids[i], nm);
                } else if (is_tag_buf(buf, use)) {
                    if (qt < 512) memcpy(queue[qt++], kids[i], 32);
                } else {
                    if (is_name_buf(buf, use)) {
                        memcpy(nm, buf, use); nm[use] = 0;
                    } else {
                        hex4_name(kids[i], nm, sizeof(nm));
                    }
                    add_entry(kids[i], nm);
                }
                continue;
            }

            /* Uncached, no name child: only fetch if it has real children (likely a tag).
             * Avoid pulling unnamed self-loop DLLs. */
            if (real_child_count(kids[i]) == 0) {
                continue;
            }

            {
                u8 buf[128];
                u32 rn = read_blob(kids[i], buf, sizeof(buf));
                if (rn >= 96) {
                    hex4_name(kids[i], nm, sizeof(nm));
                    add_entry(kids[i], nm);
                } else if (is_tag_buf(buf, rn < sizeof(buf) ? rn : sizeof(buf))) {
                    if (qt < 512) memcpy(queue[qt++], kids[i], 32);
                } else {
                    u32 use = rn < 95 ? rn : 95;
                    if (is_name_buf(buf, use)) {
                        memcpy(nm, buf, use); nm[use] = 0;
                    } else {
                        hex4_name(kids[i], nm, sizeof(nm));
                    }
                    add_entry(kids[i], nm);
                }
            }
