        if (!f) continue;
        u32 n = 0;
        fread(&n, 4, 1, f);
        if (n > 4096) n = 4096;
        g_name_n = (u32)fread(g_names, sizeof(Entry), n, f);
        fclose(f);
        return;
    }
}

static void name_load(void) {
    if (g_name_loaded) return;
    g_name_loaded = 1;
    g_name_n = 0;
    /* Hot path: flattened index on disk (no network). */
    if (name_load_tag_cache()) return;
    /* Cold: walk #TAG graph once, then persist. */
    tag_graph_build();
    if (g_name_n > 0) {
        name_save_tag_cache();
        return;
    }
    name_load_local_fallback();
}
