static TagMemo g_tag_memo[128];

static TagMemo *tag_memo_get(const u8 *key) {
    u32 h = (u32)key[0] | ((u32)key[1] << 8) | ((u32)key[2] << 16) | ((u32)key[3] << 24);
    u32 idx = h & 127u;
    for (u32 n = 0; n < 128; n++) {
