                        }
                        path_join(parent_path, nm, full, sizeof(full));
                        add_entry(kids[i], nm, full);
                    }
                } else {
                    hex4_name(kids[i], nm, sizeof(nm));
                    path_join(parent_path, nm, full, sizeof(full));
                    add_entry(kids[i], nm, full);
                }
            }
        }
    }
}

