{"code":"import hashlib, socket

SERVER=("118.25.42.70",9000)

def recv_exact(sock,size):
    out=bytearray()
    while len(out)<size:
        p=sock.recv(size-len(out))
        if not p: raise ConnectionError()
        out+=p
    return bytes(out)

def request(sock,op,body=b""):
    sock.sendall(bytes((op,))+len(body).to_bytes(4,"big")+body)
    h=recv_exact(sock,5)
    return h[0], recv_exact(sock,int.from_bytes(h[1:5],"big"))

def children_scored(sock, parent):
    st, body = request(sock, 5, parent)
    if st or len(body)<4: return []
    cnt=int.from_bytes(body[:4],"big")
    out=[]
    for i in range(cnt):
        off=4+i*40
        if off+40>len(body): break
        child=body[off:off+32]
        score=int.from_bytes(body[off+32:off+40],"big")
        out.append((child, score))
    return out

def file_get(sock,h):
    st,b=request(sock,3,h)
    return b if st==0 else None

def is_name(b):
    return b and 0<len(b)<96 and b[0]!=ord('#') and all(32<=x<127 for x in b)

def is_tag(b):
    return b and 0<len(b)<96 and b[0]==ord('#') and all(32<=x<127 for x in b)

def child_name(sock, node):
    content=file_get(sock,node)
    if is_tag(content): return content.decode(), "tag"
    if is_name(content): return content.decode(), "name"
    for ck,_ in children_scored(sock,node)[:12]:
        if ck==node: continue
        cb=file_get(sock,ck)
        if is_name(cb): return cb.decode(), "token"
    return node.hex()[:8], "opaque"

with socket.create_connection(SERVER,timeout=20) as sock:
    tag=hashlib.sha256(b"#TAG").digest()
    print("=== #TAG children (score order) ===")
    for ch,sc in children_scored(sock,tag)[:15]:
        nm,kind=child_name(sock,ch)
        print(f"  score={sc:3d} {kind:6} {nm}")

    atomic=hashlib.sha256(b"#atomic").digest()
    print("=== #atomic children (top 20) ===")
    for ch,sc in children_scored(sock,atomic)[:20]:
        nm,kind=child_name(sock,ch)
        print(f"  score={sc:3d} {kind:6} {nm}")

    ops=hashlib.sha256(b"#ops").digest()
    print("=== #ops children ===")
    for ch,sc in children_scored(sock,ops):
        nm,kind=child_name(sock,ch)
        print(f"  score={sc:3d} {kind:6} {nm}")

    var=hashlib.sha256(b"#var").digest()
    print("=== #var children ===")
    for ch,sc in children_scored(sock,var):
        nm,kind=child_name(sock,ch)
        print(f"  score={sc:3d} {kind:6} {nm}")

